    public function getSourceContext(): Source
    {
        return new Source("{% extends 'base.html.twig' %}

{% block title %}Connexion{% endblock %}

{% block body %}
    <div class=\"form-wrapper\">
        <form method=\"post\" class=\"form-box\">
            {% if error %}
                <div class=\"alert alert-danger\">{{ error.messageKey|trans(error.messageData, 'security') }}</div>
            {% endif %}

            {% if app.user %}
                <div class=\"mb-3\">
                    Vous êtes connecté en tant que {{ app.user.userIdentifier }},
                    <a href=\"{{ path('app_logout') }}\">Déconnexion</a>
                </div>
            {% endif %}

            <h1 class=\"form-title\">Connectez-vous</h1>

            <label for=\"inputEmail\" class=\"form-label\">Email :</label>
            <input
                type=\"email\"
                value=\"{{ last_username }}\"
                name=\"email\"
                id=\"inputEmail\"
                class=\"form-input\"
                autocomplete=\"email\"
                required
                autofocus
                placeholder=\"Entrez votre adresse email\"
            >

            <label for=\"inputPassword\" class=\"form-label\">Mot de passe :</label>
            <input
                type=\"password\"
                name=\"password\"
                id=\"inputPassword\"
                class=\"form-input\"
                autocomplete=\"current-password\"
                required
                placeholder=\"Entrez votre mot de passe\"
            >

            <input type=\"hidden\" name=\"_csrf_token\" value=\"{{ csrf_token('authenticate') }}\">

            <button class=\"btn btn-submit\" type=\"submit\">
                Se connecter
            </button>

            <br>
            <a href=\"{{ path('app_register') }}\" class=\"btn btn-secondary\">
                S'inscrire
            </a>
        </form>
    </div>

{% endblock %}

", "security/login.html.twig", "C:\\Users\\Daniel\\Desktop\\tp_portail\\CDA_portail_citoyen\\back\\templates\\security\\login.html.twig");
